#include <stdio.h>
#include <math.h>
#define PI 3.14159265358979323846
#define EPS 1e-9

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        double x[N], y[N];
        for (int i = 0; i < N; i++) {
            scanf("%lf %lf", &x[i], &y[i]);
        }
        double prob = 0.0;
        int total = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                for (int k = j + 1; k < N; k++) {
                    for (int l = 0; l < N; l++) {
                        if (l == i || l == j || l == k) continue;
                        double ax = x[l], ay = y[l];
                        double bx = x[i], by = y[i];
                        double cx = x[j], cy = y[j];
                        double dx = x[k], dy = y[k];
                        double D = 2 * (ax * (by - cy) + bx * (cy - ay) + cx * (ay - by));
                        double ux = ((ax * ax + ay * ay) * (by - cy) + (bx * bx + by * by) * (cy - ay) + (cx * cx + cy * cy) * (ay - by)) / D;
                        double uy = ((ax * ax + ay * ay) * (cx - bx) + (bx * bx + by * by) * (ax - cx) + (cx * cx + cy * cy) * (bx - ax)) / D;
                        double r = sqrt((ax - ux) * (ax - ux) + (ay - uy) * (ay - uy));
                        double dist = sqrt((ax - bx) * (ax - bx) + (ay - by) * (ay - by));
                        if (dist <= r + EPS) {
                            prob += 1.0;
                        }
                        total++;
                    }
                }
            }
        }
        printf("%.6f\n", prob / total);
    }
    return 0;
}

